import React, { useState } from "react";
import "../styles/GeneralChat.css";

const GeneralChat = () => {
  const [messages, setMessages] = useState([
    {
      sender: "bot",
      text: "Hello 🌱 I’m glad you reached out today. How are you feeling right now?"
    }
  ]);

  const [input, setInput] = useState("");

  const therapistReply = (userText, previousMessages) => {
    const text = userText.toLowerCase().trim();

    /* ---------------- SONG LIST ---------------- */
    const songs = `
🎧 Telugu:
• Inkem Inkem Inkem Kaavaale – Geetha Govindam  
• Vintunnava – Ye Maaya Chesave  
• Samajavaragamana (Soft Version)  
• Yuvathaku Palikina Bhasha  

🎧 Hindi:
• Khairiyat – Chhichhore  
• Agar Tum Saath Ho – Tamasha  
• Phir Le Aaya Dil (Reprise)  
• Tu Jaane Na (Soft)  

🎧 English:
• Fix You – Coldplay  
• Let It Be – The Beatles  
`;

    /* ---------------- GREETINGS ---------------- */
    if (["hi", "hello", "hey", "hai"].includes(text)) {
      return "Hello 🌼 How are you feeling right now?";
    }

    /* ---------------- STRESS → SONGS IMMEDIATELY ---------------- */
    if (
      text.includes("stressed") ||
      text.includes("stress") ||
      text.includes("feeling stressed") ||
      text.includes("overwhelmed")
    ) {
      return (
        "I’m really sorry you’re feeling this way 🤍\n\n" +
        "Listening to calming music sometimes helps when emotions feel heavy. Here are some gentle songs you can try right now:\n\n" +
        songs +
        "\nTake slow breaths while listening. I’m here with you."
      );
    }

    /* ---------------- ASKING FOR SONG ---------------- */
    if (
      text.includes("song") ||
      text.includes("music") ||
      text.includes("suggest")
    ) {
      return (
        "Of course 🌿 Here are some calming songs that many people find comforting:\n\n" +
        songs +
        "\nYou don’t have to do anything else — just listen."
      );
    }

    /* ---------------- CAUSE OF STRESS ---------------- */
    if (
      text.includes("study") ||
      text.includes("education") ||
      text.includes("exam") ||
      text.includes("college")
    ) {
      return "Studies can create a lot of pressure. What part feels most stressful right now — exams, workload, or expectations?";
    }

    if (text.includes("work") || text.includes("job")) {
      return "Work stress can be exhausting. Is it the workload, deadlines, or pressure from others?";
    }

    if (text.includes("family")) {
      return "Family pressure can feel emotionally heavy. What about your family situation is troubling you?";
    }

    if (text.includes("money") || text.includes("finance")) {
      return "Financial stress can feel scary and overwhelming. What worries you most about money right now?";
    }

    if (text.includes("future") || text.includes("career")) {
      return "Uncertainty about the future can be very stressful. What thoughts come up when you think about it?";
    }

    if (text.includes("health")) {
      return "Health-related stress can take a toll both mentally and physically. Would you like to share what’s been bothering you?";
    }

    /* ---------------- DURATION ---------------- */
    if (
      text.includes("days") ||
      text.includes("weeks") ||
      text.includes("months") ||
      text.includes("long time")
    ) {
      return "That’s a long time to carry stress. How has it been affecting your sleep, focus, or mood?";
    }

    /* ---------------- IMPACT ---------------- */
    if (
      text.includes("sleep") ||
      text.includes("tired") ||
      text.includes("focus") ||
      text.includes("headache")
    ) {
      return "That sounds really difficult 😔 When stress affects your body, it’s important to slow down. Would you like a small grounding exercise or just to talk more?";
    }

    /* ---------------- FALLBACK ---------------- */
    return "Thank you for opening up 🤍 I’m listening. Tell me a little more about what this feels like for you.";
  };

  const handleSend = () => {
    if (!input.trim()) return;

    const userMessage = { sender: "user", text: input };
    const botMessage = {
      sender: "bot",
      text: therapistReply(input, messages)
    };

    setMessages([...messages, userMessage, botMessage]);
    setInput("");
  };

  const handleKeyPress = (e) => {
    if (e.key === "Enter") {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="chat-container">
      <div className="chat-header">
        <h2 className="chat-title">💬 Professional Therapy Chat</h2>
        <p className="chat-subtitle">A safe space to talk</p>
      </div>

      <div className="chat-box">
        {messages.map((msg, index) => (
          <div
            key={index}
            className={`message-group ${
              msg.sender === "user" ? "user-group" : "therapist-group"
            }`}
          >
            <div className="message-label">
              {msg.sender === "user" ? "You" : "Therapist"}
            </div>
            <div className={`message ${msg.sender}`}>
              {msg.text}
            </div>
          </div>
        ))}
      </div>

      <div className="chat-input">
        <input
          type="text"
          placeholder="Share what you're feeling..."
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyPress={handleKeyPress}
        />
        <button onClick={handleSend}>Send</button>
      </div>
    </div>
  );
};

export default GeneralChat;
